import{_ as t,o as a,c as s,ae as o}from"./chunks/framework.Czhw_PXq.js";const d="/images/hub_add_analysis_from_proposal.png",g=JSON.parse('{"title":"Analyses","description":"","frontmatter":{},"headers":[],"relativePath":"guide/user/analyses.md","filePath":"guide/user/analyses.md"}'),n={name:"guide/user/analyses.md"};function i(r,e,l,c,u,h){return a(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="analyses" tabindex="-1">Analyses <a class="header-anchor" href="#analyses" aria-label="Permalink to &quot;Analyses&quot;">​</a></h1><p>Analyses are distributed computations within a <a href="/guide/user/projects.html">project</a>. They define the code, configuration, and target nodes for a federated computation.</p><h2 id="creating-an-analysis" tabindex="-1">Creating an Analysis <a class="header-anchor" href="#creating-an-analysis" aria-label="Permalink to &quot;Creating an Analysis&quot;">​</a></h2><p><img src="'+d+'" alt="Add analysis from project"></p><p>An analysis requires:</p><ul><li>A parent <strong>project</strong> (must be approved)</li><li>A <strong>master image</strong> — the base Docker image for execution</li><li><strong>Analysis code</strong> — uploaded to a storage bucket and built into a container</li></ul><h2 id="execution-flow" tabindex="-1">Execution Flow <a class="header-anchor" href="#execution-flow" aria-label="Permalink to &quot;Execution Flow&quot;">​</a></h2><p>Once <a href="/guide/user/approval.html">approved</a>, an analysis goes through:</p><ol><li><strong>Configuration</strong> — storage buckets are provisioned, configuration is locked</li><li><strong>Build</strong> — the worker builds a Docker image from the analysis code and master image</li><li><strong>Distribute</strong> — the container image is pushed to target node registries</li><li><strong>Execute</strong> — nodes pull and run the container against their local data</li><li><strong>Complete</strong> — results are collected and stored</li></ol><h2 id="api-endpoints" tabindex="-1">API Endpoints <a class="header-anchor" href="#api-endpoints" aria-label="Permalink to &quot;API Endpoints&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Endpoint</th><th>Description</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/analyses</code></td><td>List analyses</td></tr><tr><td><code>POST</code></td><td><code>/analyses</code></td><td>Create analysis</td></tr><tr><td><code>GET</code></td><td><code>/analyses/:id</code></td><td>Get analysis details</td></tr><tr><td><code>PUT</code></td><td><code>/analyses/:id</code></td><td>Update analysis</td></tr><tr><td><code>DELETE</code></td><td><code>/analyses/:id</code></td><td>Delete analysis</td></tr><tr><td><code>GET</code></td><td><code>/analysis-buckets</code></td><td>List analysis storage buckets</td></tr><tr><td><code>GET</code></td><td><code>/analysis-bucket-files</code></td><td>List analysis bucket files</td></tr></tbody></table><h2 id="analysis-buckets" tabindex="-1">Analysis Buckets <a class="header-anchor" href="#analysis-buckets" aria-label="Permalink to &quot;Analysis Buckets&quot;">​</a></h2><p>Each analysis can have associated storage buckets for input data, code, and results. Buckets are managed by the <a href="/reference/storage/">Storage service</a> and provisioned automatically during the configuration phase.</p>',13)])])}const y=t(n,[["render",i]]);export{g as __pageData,y as default};
